SELECT MEMBER_NAME, REVIEW_TEXT, DATE_FORMAT(R.REVIEW_DATE, '%Y-%m-%d') AS REVIEW_DATE FROM( SELECT MP.MEMBER_ID, MEMBER_NAME, COUNT(REVIEW_ID) AS CNT, RANK() OVER(ORDER BY COUNT(REVIEW_ID) DESC) AS RNK FROM MEMBER_PROFILE MP JOIN REST_REVIEW RR ON MP.MEMBER_ID = RR.MEMBER_ID GROUP BY MP.MEMBER_ID, MEMBER_NAME ) T JOIN REST_REVIEW R ON T.MEMBER_ID = R.MEMBER_ID WHERE RNK = 1 ORDER BY REVIEW_DATE, REVIEW_TEXT